import{_ as e,o as t,c as _,ae as a}from"./chunks/framework.Bn0jkBmj.js";const m=JSON.parse('{"title":"我混母婴圈17年，最怕“猜”","description":null,"frontmatter":{"title":null,"description":null},"headers":[],"relativePath":"scl/我混母婴圈17年，最怕“猜”.md","filePath":"scl/我混母婴圈17年，最怕“猜”.md"}'),r={name:"scl/我混母婴圈17年，最怕“猜”.md"};function l(n,p,o,s,c,i){return t(),_("div",null,[...p[0]||(p[0]=[a('<h1 id="我混母婴圈17年-最怕-猜" tabindex="-1">我混母婴圈17年，最怕“猜” <a class="header-anchor" href="#我混母婴圈17年-最怕-猜" aria-label="Permalink to &quot;我混母婴圈17年，最怕“猜”&quot;">​</a></h1><p>凌晨3点，宝宝突然哭醒， 最闹心的不是“吵”， 是全家围着宝宝“有奖竞猜”：</p><p>饿了？热了？ 肠绞痛？生病了？ 猜对了，是运气； 猜错了，就是全家一顿折腾。</p><p>这是很多育婴员， 向我描述的场景。</p><p>我在南昌做家政、 做母婴培训17年， 同行都是热情亲切的姐妹👩；</p><p>我，唯一的光头男， 混在里面，有点小别扭；</p><p>因为，大家都在“猜哭声”。 当然也包括、 已经有一定经验的我。</p><p>经验—— 给得了方向， 给不了确定性， 凭经验，心里总觉得没底。</p><p>那么，各类哭声， 到底有没有规律❓</p><p>如果有， 又怎么原汁原味地 告诉家长和学员呢？</p><p>直到有一天， 我又在随手翻听录音时， 突然反应过来： 答案不就在—— 这6000多条哭声里？</p><p>💡我有思路了——</p><p>让AI听所有哭声录音， 如果AI能找到规律， “翻译”新的哭声， 不就是顺理成章了吗？</p><p>这样， 宝妈们就少一些盲猜， 少一些，凌晨3点的慌张。</p><p>想到就干，反正素材是现成的。 没想到，第一步，就撞了墙——</p><p>我这台T470笔记本，没有GPU, 算力达不到，完全跑不动。</p><p>听着电脑风扇的轰鸣声， 看着万元的英伟达显卡报价， 我急的干瞪眼……</p>',17)])])}const u=e(r,[["render",l]]);export{m as __pageData,u as default};
